@app.post("/api/tokens/store")
async def store_token(token: str, user_id: str, scopes: list[str] = None, ttl: int = 3600):
    """
    Admin endpoint to store a token in Redis (for testing/setup).
    In production, this would be handled by your OAuth server.
    """
    if not token or len(token) < 32:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="Token must be at least 32 characters"
        )
    
    token_hash = hash_token(token)
    
    try:
        async with redis_client.pipeline(transaction=True) as pipe:
            pipe.setex(f"token:{token_hash}", ttl, "valid")
            pipe.hset(f"token:{token_hash}:user", mapping={
                "user_id": user_id,
                "scopes": ",".join(scopes) if scopes else ""
            })
            pipe.expire(f"token:{token_hash}:user", ttl)
            await pipe.execute()
        
        return {
            "message": "Token stored successfully",
            "expires_in": ttl
        }
    except redis.RedisError:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Storage service temporarily unavailable"
        )

